mapper.update:
update wf_cc_process_instance 
set status = #{status}, 
finish_Time = #{finishTime} 
where instance_Id = #{instanceId} and actor_Id = #{actorId}

mapper.select:
		select instance_Id, actor_Id, creator, create_Time, finish_Time, status 
		from wf_cc_process_instance 


                instance_Id = #{instanceId}


                and actor_Id in

                    #{actorId}

		select count(id) from wf_cc_process_instance cc left join wf_historic_process_instance o on cc.instance_Id = o.id


                cc.actor_Id in

                    #{operator}



                and cc.status = #{request.state}


                and process_Id = #{request.processId}


                and parent_Id = #{request.parentId}


                and cc.create_Time >= #{request.createTimeStart}


                and cc.create_Time <= #{request.createTimeEnd}

		select id, process_Id, state, priority, cc.creator, cc.create_Time, end_Time, parent_Id, expire_Time,
		variable
		from wf_cc_process_instance cc left join wf_historic_process_instance o on cc.instance_Id = o.id


                cc.actor_Id in

                    #{operator}



                and cc.status = #{request.state}


                and process_Id = #{request.processId}


                and parent_Id = #{request.parentId}


                and cc.create_Time >= #{request.createTimeStart}


                and cc.create_Time <= #{request.createTimeEnd}



            order by #{request.sortString}

		limit #{rowOffset}, #{request.pageSize}
